def action_populate_checklist_items(self):
    self.ensure_one()
    if not self.job_id:
        return

    # Get templates from job position, or fall back to default templates
    templates = self.job_id.checklist_template_ids
    if not templates:
        # Use default templates (where job_id is empty)
        # Include all statuses to ensure new templates are loaded
        templates = self.env['hr.job.checklist.template'].search([
            ('job_id', '=', False)
        ], order='sequence, id')

    if not templates:
        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'No Templates Found',
                'message': 'No checklist templates found for this job position or in default templates.',
                'type': 'warning',
            }
        }

    existing_templates = self.checklist_item_ids.mapped('template_id')
    created_count = 0

    for template in templates:
        if template not in existing_templates:
            self.env['hr.applicant.checklist.item'].create({
                'applicant_id': self.id,
                'template_id': template.id,
                'name': template.name,
                'sequence': template.sequence,
                'upload_by': template.upload_by,
            })
            created_count += 1

    # Show success message with count
    if created_count > 0:
        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Checklist Loaded',
                'message': f'{created_count} checklist item(s) added successfully.',
                'type': 'success',
            }
        }
